function toggleTheme(){const e=document.documentElement,t=e.getAttribute("data-theme"),n=t==="dark"?"light":"dark";e.setAttribute("data-theme",n);localStorage.setItem("erp-theme",n);updateThemeUI(n)}function updateThemeUI(e){const t=document.getElementById("theme-icon");t&&(e==="dark"?(t.classList.remove("fa-moon"),t.classList.add("fa-sun"),t.style.color="#ffcf40"):(t.classList.remove("fa-sun"),t.classList.add("fa-moon"),t.style.color="inherit"))}(function(){const e=localStorage.getItem("erp-theme")||"light";document.documentElement.setAttribute("data-theme",e);window.addEventListener("DOMContentLoaded",()=>{updateThemeUI(e)})})();
